  const THEME = {
    current: 'dark',
    init() {
      const saved = localStorage.getItem('techon-theme');
      if (saved === 'light' || saved === 'dark') {
        this.current = saved;
      }
      document.documentElement.setAttribute('data-theme', this.current);
    },
    toggle() {
      this.current = this.current === 'dark' ? 'light' : 'dark';
      document.documentElement.setAttribute('data-theme', this.current);
      localStorage.setItem('techon-theme', this.current);
    }
  };

